import * as E from 'fp-ts/Either';

interface Email { readonly address: string }

class ValidationError { readonly _tag = 'ValidationError' as const; constructor(readonly field: string) {} }

const nonEmpty = (s: string): E.Either<ValidationError, string> =>
  s.trim().length > 0 ? E.right(s) : E.left(new ValidationError('empty'));
const hasAt = (s: string): E.Either<ValidationError, string> =>
  s.includes('@') ? E.right(s) : E.left(new ValidationError('missing @'));
const underMaxLen = (s: string): E.Either<ValidationError, string> =>
  s.length < 254 ? E.right(s) : E.left(new ValidationError('>= 254'));

export const validateEmail = (s: string): E.Either<ValidationError, Email> =>
  pipe(
    nonEmpty(s),
    E.chainW(hasAt),
    E.chainW(underMaxLen),
    E.map((addr) => ({ address: addr })),
  );
```

All three validators share `ValidationError` in this context, so `E.chainW` is equivalent to plain `E.chain` — both widen on the left union.

