import { Observable } from 'rxjs';
import { debounceTime, distinctUntilChanged, filter, switchMap } from 'rxjs/operators';

interface Result {
  id: string;
  title: string;
}

declare function searchApi$(q: string): Observable<ReadonlyArray<Result>>;

export const typeahead$ = (
  input$: Observable<string>
): Observable<ReadonlyArray<Result>> =>
  input$.pipe(
    debounceTime(250),
    distinctUntilChanged(),
    filter((q: string) => q.trim().length > 0),
    switchMap((q: string) => searchApi$(q))
  );
```

`switchMap` cancels the previous `searchApi$` when a new query arrives — in-flight request discarded, new one dispatched. `mergeMap` here would race the two requests and whichever returned first would win, which is what you usually want with parallel APIs but what you almost always want with a typeahead: the first answer wins and the second is cancelled.

