export type ShoppingCartState =
  | { status: "empty" }
  | { status: "shopping"; id: string; items: ReadonlyArray<string> }
  | { status: "checked-out"; id: string; items: ReadonlyArray<string> };

export type ShoppingCartEvent =
  | { type: "CartCreated"; id: string }
  | { type: "ItemAdded"; sku: string }
  | { type: "ItemRemoved"; sku: string }
  | { type: "CartCheckedOut" };

export const initialShoppingCart: ShoppingCartState = { status: "empty" };

export function evolve(state: ShoppingCartState, event: ShoppingCartEvent): ShoppingCartState {
  switch (event.type) {
    case "CartCreated":
      return { status: "shopping", id: event.id, items: [] };
    case "ItemAdded":
      if (state.status !== "shopping") return state;
      return { ...state, items: [...state.items, event.sku] };
    case "ItemRemoved":
      if (state.status !== "shopping") return state;
      return { ...state, items: state.items.filter((sku) => sku !== event.sku) };
    case "CartCheckedOut":
      if (state.status !== "shopping") return state;
      return { status: "checked-out", id: state.id, items: state.items };
    default: { const _n: never = event; return state; }
  }
}

export function aggregate(events: ReadonlyArray<ShoppingCartEvent>): ShoppingCartState {
  return events.reduce(evolve, initialShoppingCart);
}
