export type ChapterHouseEvent =
  | { type: "opened"; houseId: string; name: string }
  | { type: "renamed"; name: string };

export type ChapterHouseCommand =
  | { type: "open"; houseId: string; name: string }
  | { type: "rename"; name: string };

export interface ChapterHouseState {
  houseId: string;
  name: string;
}

const initial: ChapterHouseState = { houseId: "", name: "" };

function evolve(state: ChapterHouseState, event: ChapterHouseEvent): ChapterHouseState {
  switch (event.type) {
    case "opened":
      return { houseId: event.houseId, name: event.name };
    case "renamed":
      return { ...state, name: event.name };
    default: {
      const _: never = event;
      return _;
    }
  }
}

function decide(command: ChapterHouseCommand, state: ChapterHouseState): ChapterHouseEvent[] {
  switch (command.type) {
    case "open":
      if (state.houseId !== "") throw new Error("already open");
      return [{ type: "opened", houseId: command.houseId, name: command.name }];
    case "rename":
      if (state.houseId === "") throw new Error("not open");
      return [{ type: "renamed", name: command.name }];
    default: {
      const _: never = command;
      return _;
    }
  }
}

export interface StoredEvent<E> { revision: bigint; event: E }
export interface EventStore<E> {
  readStream(stream: string): Promise<StoredEvent<E>[]>;
  appendToStream(stream: string, events: E[], opts: { expectedRevision: bigint | "no_stream" }): Promise<void>;
}

export async function handle(
  command: ChapterHouseCommand,
  ctx: { streamName: string; eventStore: EventStore<ChapterHouseEvent> },
): Promise<void> {
  const stored = await ctx.eventStore.readStream(ctx.streamName);
  const state = stored.reduce<ChapterHouseState>((s, r) => evolve(s, r.event), initial);
  const events = decide(command, state);
  const expected: bigint | "no_stream" = stored.length === 0 ? "no_stream" : stored[stored.length - 1].revision;
  await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: expected });
}
