Snapshots trade storage cost for replay cost: a single serialized blob beats re-emitting every event, but the blob itself becomes a unit of versioned schema. Include a `version` tag so a loader that encounters a newer snapshot than its schema can signal a schema update. Downstream, a projection keeps the read model in sync with whatever events the aggregate still emits.

```typescript
export type Snapshot<S> = { version: number; state: S };
export type LoadInput<S, E> =
  | { source: "snapshot"; snap: Snapshot<S> }
  | { source: "events"; events: ReadonlyArray<E> };
export interface Aggregate<S, E> {
  readonly initialState: S;
  evolve(state: S, event: E): S;
}
export function loadAggregate<S, E>(
  agg: Aggregate<S, E>,
  input: LoadInput<S, E>,
): S {
  switch (input.source) {
    case "snapshot": return input.snap.state;
    case "events": return input.events.reduce<S>(agg.evolve, agg.initialState);
    default: { const _n: never = input; return agg.initialState; }
  }
}
```
